function cs(){let gc=0,s=0,gg=0;FAMILY.forEach(b=>{gc+=b.grandchildren.length;b.grandchildren.forEach(m=>{s+=m.sons.length;if(m.greatGrandsons)Object.values(m.greatGrandsons).forEach(a=>gg+=a.length)})});return{sons:FAMILY.length,gc,gcS:s,gg,total:FAMILY.length+gc+s+gg}}
