// ─── Scroll reveal hook ───
function useReveal(){
  const ref=useRef(null);const[vis,setVis]=useState(false);
  useEffect(()=>{
    const el=ref.current;if(!el)return;
    const obs=new IntersectionObserver(([e])=>{if(e.isIntersecting){setVis(true);obs.unobserve(el)}},{threshold:.15,rootMargin:'0px 0px -40px 0px'});
    obs.observe(el);return()=>obs.disconnect();
  },[]);
  return[ref,vis];
}
function R({children,delay=0,className=''}){
  const[ref,vis]=useReveal();
  return <div ref={ref} className={className} style={{opacity:vis?1:0,transform:vis?'translateY(0)':'translateY(30px)',transition:`opacity .7s cubic-bezier(.16,1,.3,1) ${delay}s, transform .7s cubic-bezier(.16,1,.3,1) ${delay}s`}}>{children}</div>;
}

// ─── Counter animation ───
function Counter({target,suffix=''}){
  const[val,setVal]=useState(0);const[ref,vis]=useReveal();
  useEffect(()=>{
    if(!vis)return;let start=0;const dur=1800;const st=Date.now();
    const tick=()=>{const p=Math.min((Date.now()-st)/dur,1);const ease=1-Math.pow(1-p,3);setVal(Math.floor(ease*target));if(p<1)requestAnimationFrame(tick)};
    tick();
  },[vis,target]);
  return <span ref={ref}>{val>0?'+':''}{val}{suffix}</span>;
}

